import sqlite3

def advanced_search(query_params, table_name):
    conn = sqlite3.connect('example.db')
    cursor = conn.cursor()
    
    fields = []
    values = []
    conditions = []
    
    for param in query_params:
        field = param['field']
        op = param['op']
        value = param['value']
        
        if op == '=':
            conditions.append(f"{field} = ?")
        elif op == '>':
            conditions.append(f"{field} > ?")
        elif op == '<':
            conditions.append(f"{field} < ?")
        elif op == 'LIKE':
            conditions.append(f"{field} LIKE ?")
        
        fields.append(field)
        values.append(value)
    
    query = f"SELECT * FROM {table_name} WHERE {' AND '.join(conditions)}"
    
    cursor.execute(query, values)
    results = cursor.fetchall()
    
    conn.close()
    return results

# Example usage
query_params = [
    {'field': 'age', 'op': '>', 'value': 18},
    {'field': 'city', 'op': '=', 'value': 'NYC'}
]
